#include<stdio.h>
#include<string.h>
char s[220];
long n,len;
long check(long a)
{
    long i;
    for(i=1;i<=a-n;i++)
        if(s[len-i]!=s[len-i-a])
            return 0;
    return 1;
}
int main()
{
    long i,k,j,ans=0,key,max,min,temp=0;
    scanf("%s",s);
    len=strlen(s);
    scanf("%ld",&n);

    if(n>len)
        min=(len+n)/2;
    else min=n;

    max=(len+n)/2;
    for(i=0;i<len;i++)
        for(j=1;j*2+i<=len;j++)
            {   key=1;
                for(k=1;k<=j;k++)
                    if(s[i+k-1]!=s[i+k+j-1])
                    key=0;
                if(key==1)
                    if(j>temp)
                        temp=j;
            }


    for(i=max;(i>=min)&&(ans==0);i--)
        if(check(i)==1)
            ans=i;
    if(min>ans)
        ans=min;
    if(temp>ans)
        ans=temp;
    printf("%ld",2*ans);

return 0;
}

