macro_rules! parse_line {
    ($t: ty) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let a_str = a_str.trim();
        a_str.parse::<$t>().expect("parse error")
    });
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

macro_rules! parse_line_to_vec {
    ($t: ty) => {{
        let mut a_str = String::new();
        std::io::stdin().read_line(&mut a_str).expect("read error");
        (a_str
            .split_whitespace()
            .map(|x| x.parse::<$t>().unwrap())
            .collect::<Vec<$t>>())
    }};
}

fn gcd(mut a: i64, mut b: i64) -> i64 {
    while a != 0 {
        b %= a;
        std::mem::swap(&mut a, &mut b);
    }
    b
}

fn solve() {
    let s: Vec<_> = parse_line!(String).bytes().collect();
    let k = parse_line!(usize);
    let mut ans = k - k % 2;
    for i in 0..s.len() {
        for j in (i + 2..=s.len() + k).step_by(2) {
            let mut ok = true;
            let n = (j - i) / 2;
            for k in i..i + n {
                if k + n >= s.len() {
                    break;
                }
                if s[k] != s[k + n] {
                    ok = false;
                    break;
                }
            }
            if ok {
                ans = std::cmp::max(ans, j - i);
            }
        }
    }
    println!("{}", ans);
}

fn main() {
    let tests = 1; // parse_line!(usize);
    for _ in 0..tests {
        solve();
    }
}
